import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { chaptersAPI, progressAPI } from '../services/api';
import { useLanguage } from '../contexts/LanguageContext';
import './Learn.css';

const STATUS = {
  completed:     { color: '#16a34a', bg: '#dcfce7', label: 'Completed',   paLabel: 'ਪੂਰਾ' },
  'in-progress': { color: '#2563eb', bg: '#dbeafe', label: 'In progress', paLabel: 'ਜਾਰੀ' },
  'not-started': { color: '#94a3b8', bg: '#f1f5f9', label: 'Not started', paLabel: 'ਸ਼ੁਰੂ ਨਹੀਂ' },
};

const TYPE_STYLE = {
  'intro':            { bg: '#ede9fe', color: '#7c3aed' },
  'random-words':     { bg: '#dbeafe', color: '#2563eb' },
  'meaningful-words': { bg: '#cffafe', color: '#0891b2' },
  'sentences':        { bg: '#fef3c7', color: '#d97706' },
  'paragraph':        { bg: '#dcfce7', color: '#16a34a' },
};

const ArrowC = ({ open, color }) => (
  <svg width="20" height="20" viewBox="0 0 20 20" fill="none"
    style={{ transition: 'transform 0.22s ease', transform: `rotate(${open ? 180 : 0}deg)`, flexShrink: 0 }}>
    <circle cx="10" cy="10" r="9" stroke="#e2e8f0" strokeWidth="1" />
    <path d={open ? 'M6.5 11.5l3.5-3.5 3.5 3.5' : 'M6.5 8.5l3.5 3.5 3.5-3.5'}
      stroke={color || '#94a3b8'} strokeWidth="1.4" strokeLinecap="round" strokeLinejoin="round" />
  </svg>
);

const Learn = () => {
  const navigate = useNavigate();
  const { language } = useLanguage();
  const isPa = language === 'punjabi';

  const [chapters, setChapters]     = useState([]);
  const [progress, setProgress]     = useState({});
  const [loading, setLoading]       = useState(true);
  const [error, setError]           = useState(null);
  const [openMap, setOpenMap]       = useState({});

  useEffect(() => { loadData(); }, [language]);

  const loadData = async () => {
    setLoading(true);
    try {
      const [chapRes, progRes] = await Promise.all([
        chaptersAPI.getAll(language),
        progressAPI.getLessons(language),
      ]);
      const chapList = chapRes.data || [];
      setChapters(chapList);

      const done = {};
      (progRes.data || []).forEach(p => { done[`${p.chapterId}_${p.lessonId}`] = true; });
      setProgress(done);

      const init = {};
      chapList.forEach((ch, i) => { if (i < 2) init[ch._id] = true; });
      setOpenMap(init);
    } catch {
      setError('Failed to load chapters');
    } finally {
      setLoading(false);
    }
  };

  const isDone = (chId, lId) => !!progress[`${chId}_${lId}`];

  const chapterStats = (ch) => {
    const total = ch.lessons?.length || 0;
    const done  = ch.lessons?.filter(l => isDone(ch._id, l._id)).length || 0;
    const pct   = total ? Math.round((done / total) * 100) : 0;
    const status = done === 0 ? 'not-started' : done === total ? 'completed' : 'in-progress';
    return { total, done, pct, status };
  };

  if (loading) return <div className="learn-loading">Loading...</div>;
  if (error)   return <div className="learn-error">{error}</div>;

  return (
    <div className="learn-container">
      <div className="learn-header">
        <h1 className="learn-title" style={isPa ? { fontFamily: "'Raavi','Noto Sans Gurmukhi',sans-serif" } : undefined}>
          {isPa ? 'ਸਿੱਖੋ — ਅਧਿਆਏ ਅਤੇ ਪਾਠ' : 'Learn Mode — Chapters & Lessons'}
        </h1>
        <p className="learn-subtitle" style={isPa ? { fontFamily: "'Raavi','Noto Sans Gurmukhi',sans-serif" } : undefined}>
          {isPa ? 'ਟੱਚ ਟਾਈਪਿੰਗ ਮਾਹਿਰ ਬਣਨ ਲਈ ਪਾਠਾਂ ਵਿੱਚੋਂ ਅੱਗੇ ਵਧੋ' : 'Progress through structured lessons to master touch typing'}
        </p>
      </div>

      <div className="learn-chapters">
        {chapters.map((ch) => {
          const { pct, status } = chapterStats(ch);
          const { color, bg, label, paLabel } = STATUS[status];
          const isOpen = !!openMap[ch._id];

          return (
            <div key={ch._id} className="chapter-card">
              {/* Header */}
              <div className="chapter-header" onClick={() => setOpenMap(p => ({ ...p, [ch._id]: !p[ch._id] }))}>
                <div className="chapter-num" style={{ background: bg, color }}>{ch.chapterNumber}</div>
                <div className="chapter-meta">
                  <div className="chapter-title" style={isPa ? { fontFamily: "'Raavi','Noto Sans Gurmukhi',sans-serif" } : undefined}>
                    {isPa ? `ਅਧਿਆਇ ${ch.chapterNumber}: ${ch.chapterTitle}` : `Chapter ${ch.chapterNumber}: ${ch.chapterTitle}`}
                  </div>
                  <div className="chapter-progress-row">
                    <div className="chapter-track">
                      <div className="chapter-fill" style={{ width: `${pct}%`, background: color }} />
                    </div>
                    <span className="chapter-pct" style={{ color }}>{pct}%</span>
                  </div>
                </div>
                <span className="status-badge" style={{ background: bg, color }}>
                  {isPa ? paLabel : label}
                </span>
                <ArrowC open={isOpen} color={color} />
              </div>

              {/* Lessons */}
              {isOpen && (
                <div className="chapter-body">
                  {(ch.lessons || []).map((lesson, li) => {
                    const done = isDone(ch._id, lesson._id);
                    const ts = TYPE_STYLE[lesson.lessonType] || { bg: '#f1f5f9', color: '#64748b' };
                    return (
                      <div key={lesson._id} className="lesson-row">
                        <span className="lesson-num">{li + 1}</span>
                        <div className="lesson-tick" style={{ background: done ? '#16a34a' : '#e2e8f0' }}>
                          {done && <svg width="10" height="10" viewBox="0 0 10 10"><path d="M2 5l2.5 2.5L8 3" stroke="#fff" strokeWidth="1.5" fill="none" strokeLinecap="round" /></svg>}
                        </div>
                        <span className="lesson-title" style={isPa ? { fontFamily: "'Raavi','Noto Sans Gurmukhi',sans-serif" } : undefined}>
                          {lesson.lessonTitle}
                        </span>
                        <span className="lesson-type" style={{ background: ts.bg, color: ts.color }}>
                          {lesson.lessonType}
                        </span>
                        <button
                          className={`lesson-btn ${done ? 'btn-retake' : 'btn-start'}`}
                          onClick={() => navigate(`/lesson/${ch._id}/${lesson._id}`)}>
                          {done ? (isPa ? 'ਦੁਬਾਰਾ' : 'Retake') : (isPa ? 'ਸ਼ੁਰੂ' : 'Start')}
                        </button>
                      </div>
                    );
                  })}
                </div>
              )}
            </div>
          );
        })}
      </div>
    </div>
  );
};

export default Learn;
